    `kyc_review_date` DATE COMMENT 'The scheduled date for the next periodic KYC review of this counterparty.',
    `kyc_status` STRING COMMENT 'The current status of the Know Your Customer due diligence process for this counterparty.',
    `legal_name` STRING COMMENT 'The official registered legal name of the counterparty as it appears on legal documents and contracts.',
    `lei_code` STRING COMMENT 'The 20-character ISO 17442 Legal Entity Identifier for financial transaction reporting and regulatory compliance.',
    `modified_timestamp` TIMESTAMP COMMENT 'The timestamp when this counterparty record was last modified or updated.',
    `payment_terms_days` STRING COMMENT 'The standard number of days allowed for payment settlement with this counterparty (e.g., Net 30, Net 60).',
    `postal_code` STRING COMMENT 'The postal or ZIP code of the counterpartys primary business address.',
    `preferred_currency_code` STRING COMMENT 'The three-letter ISO currency code representing the counterpartys preferred transaction currency.',
    `primary_contact_name` STRING COMMENT 'The full name of the primary business contact person at the counterparty organization.',
    `primary_contact_title` STRING COMMENT 'The job title or role of the primary business contact person at the counterparty organization.',
    `primary_email` STRING COMMENT 'The primary email address for business communications with the counterparty.',
    `primary_phone` STRING COMMENT 'The primary telephone contact number for the counterparty.',
    `relationship_status` STRING COMMENT 'The current status of the business relationship with this counterparty.',
    `risk_classification` STRING COMMENT 'The assessed risk level of conducting business with this counterparty based on financial, operational, and compliance factors.',
    `sanctions_screening_date` DATE COMMENT 'The date when the most recent sanctions screening was performed for this counterparty.',
    `sanctions_screening_status` STRING COMMENT 'The result of the most recent sanctions list screening for this counterparty.',
    `state_province` STRING COMMENT 'The state, province, or administrative region of the counterpartys primary business address.',
    `tax_identifier` STRING COMMENT 'The primary tax identification number for the counterparty (e.g., EIN, SSN, VAT number) used for tax reporting and compliance.',
    `termination_date` DATE COMMENT 'The date when the business relationship with this counterparty was terminated or is scheduled to terminate.',
    `trade_name` STRING COMMENT 'The commercial or trade name under which the counterparty operates, if different from legal name.',
    `vendor_number` STRING COMMENT 'The unique vendor identification number assigned in the accounts payable system for vendor counterparties.',
    `website_url` STRING COMMENT 'The official website URL of the counterparty organization.',
    CONSTRAINT pk_counterparty PRIMARY KEY(`counterparty_id`)
) COMMENT 'Master reference table for counterparty. Referenced by counterparty_id.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`finance`.`chart_of_accounts` (
    `chart_of_accounts_id` BIGINT COMMENT 'Primary key for chart_of_accounts',
    `parent_chart_of_accounts_id` BIGINT COMMENT 'Self-referencing FK on chart_of_accounts (parent_chart_of_accounts_id)',
    `account_category` STRING COMMENT 'The sub-classification within the account type that provides additional granularity for financial statement presentation and analysis (e.g., current vs. fixed assets, operating vs. non-operating revenue).',
    `account_group` STRING COMMENT 'The grouping code used to aggregate similar accounts for reporting and analysis purposes. Used in SAP S/4HANA for account determination and financial statement version assignment.',
    `account_name` STRING COMMENT 'The descriptive name of the general ledger account that clearly identifies its purpose and usage in financial reporting.',
    `account_number` STRING COMMENT 'The unique general ledger account number used to identify the account in the chart of accounts. This is the primary business identifier for financial transactions and reporting.',
    `account_type` STRING COMMENT 'The fundamental accounting classification of the account based on the accounting equation and financial statement presentation (asset, liability, equity, revenue, or expense).',
    `approval_required` BOOLEAN COMMENT 'Indicates whether changes to this account require formal approval workflow before becoming effective, typically required for SOX-relevant accounts and accounts used in external financial reporting.',
    `approval_timestamp` TIMESTAMP COMMENT 'The timestamp when this chart of accounts entry was approved. Used for audit trail and compliance documentation of the approval workflow.',
    `approved_by_user` STRING COMMENT 'The user ID of the approver who authorized the creation or modification of this chart of accounts entry. Required for SOX compliance and segregation of duties controls.',
    `arr_relevant` BOOLEAN COMMENT 'Indicates whether revenue posted to this account contributes to Annual Recurring Revenue (ARR) calculations for subscription-based business model tracking and investor reporting.',
    `balance_sheet_classification` STRING COMMENT 'Indicates whether the account is classified as current (within 12 months) or non-current (beyond 12 months) on the balance sheet, or not applicable for income statement accounts.',
    `budget_tracking_enabled` BOOLEAN COMMENT 'Indicates whether budget vs. actual tracking is enabled for this account in the financial planning and analysis (FP&A) system for variance analysis and budget control.',
    `cash_flow_classification` STRING COMMENT 'The classification of this account for cash flow statement presentation: operating activities, investing activities, financing activities, or not applicable for non-cash accounts.',
    `consolidation_account` STRING COMMENT 'The corresponding account number in the corporate consolidation chart of accounts used for group-level financial consolidation and elimination of intercompany transactions.',
    `cost_center_required` BOOLEAN COMMENT 'Indicates whether a cost center assignment is mandatory when posting transactions to this account for expense tracking and departmental cost allocation.',
    `cost_element` STRING COMMENT 'The cost element code in SAP Controlling (CO) module that links this general ledger account to cost accounting for expense allocation, cost center assignment, and profitability analysis.',
    `created_by_user` STRING COMMENT 'The user ID of the person who created this chart of accounts entry. Required for SOX compliance and master data governance audit trails.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this chart of accounts entry was first created in the system. Used for audit trail and master data governance tracking.',
    `currency_code` STRING COMMENT 'The three-letter ISO 4217 currency code for accounts that are maintained in a specific currency. For multi-currency accounts, this may be null or indicate the local currency.',
    `chart_of_accounts_description` STRING COMMENT 'Detailed description of the accounts purpose, usage guidelines, and the types of transactions that should be posted to this account for proper financial classification and reporting.',
    `ebitda_classification` STRING COMMENT 'Indicates whether this account is included in or excluded from EBITDA calculations for management reporting and investor relations. Depreciation, amortization, interest, and tax accounts are excluded.',
    `financial_statement_line` STRING COMMENT 'The specific line item on the financial statement (balance sheet, income statement, cash flow statement) where this account balance is reported for external financial reporting.',
    `functional_area` STRING COMMENT 'The functional area classification used for segment reporting and financial statement version assignment in SAP S/4HANA, representing business functions such as production, sales, administration, or research and development.',
    `intercompany_indicator` BOOLEAN COMMENT 'Indicates whether this account is used for intercompany transactions that require elimination during corporate consolidation for group financial reporting.',
    `modified_by_user` STRING COMMENT 'The user ID of the person who last modified this chart of accounts entry. Required for SOX compliance and change management audit trails.',
    `modified_timestamp` TIMESTAMP COMMENT 'The timestamp when this chart of accounts entry was last modified. Used for change tracking, audit compliance, and master data governance.',
    `normal_balance` STRING COMMENT 'Indicates whether the account normally carries a debit or credit balance based on its account type. Assets and expenses have debit balances; liabilities, equity, and revenue have credit balances.',
    `posting_allowed` BOOLEAN COMMENT 'Boolean flag indicating whether direct transaction postings are allowed to this account. Some accounts may be used only for consolidation or reporting purposes and do not accept direct postings.',
    `profit_center_required` BOOLEAN COMMENT 'Indicates whether a profit center assignment is mandatory when posting transactions to this account for segment reporting and profitability analysis.',
    `reconciliation_account` BOOLEAN COMMENT 'Indicates whether this is a reconciliation account that is automatically updated from subsidiary ledgers (accounts receivable, accounts payable, fixed assets) and cannot be posted to directly.',
    `revenue_recognition_method` STRING COMMENT 'For revenue accounts, indicates the revenue recognition method under ASC 606 / IFRS 15: recognized at a point in time when control transfers, or over time as performance obligations are satisfied.',
    `sox_relevant` BOOLEAN COMMENT 'Indicates whether this account is subject to Sarbanes-Oxley Act internal control requirements and requires enhanced documentation, approval workflows, and audit trails for compliance with SOX Section 404.',
    `chart_of_accounts_status` STRING COMMENT 'The current lifecycle status of the chart of accounts entry indicating whether it is available for posting transactions, blocked from use, or pending approval for activation.',
    `tax_category` STRING COMMENT 'The tax treatment category for this account indicating whether transactions posted to it are subject to sales tax, VAT, or other tax regulations, or are tax-exempt.',
    `valid_from_date` DATE COMMENT 'The date from which this chart of accounts entry becomes effective and available for transaction posting. Used for time-dependent master data management.',
    `valid_to_date` DATE COMMENT 'The date until which this chart of accounts entry remains effective. After this date, the account is no longer available for new postings. Null indicates no expiration.',
    CONSTRAINT pk_chart_of_accounts PRIMARY KEY(`chart_of_accounts_id`)
) COMMENT 'Master reference table for chart_of_accounts. Referenced by chart_of_accounts_id.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`finance`.`payment_program` (
    `payment_program_id` BIGINT COMMENT 'Primary key for payment_program',
    `superseded_payment_program_id` BIGINT COMMENT 'Self-referencing FK on payment_program (superseded_payment_program_id)',
    `approval_required_flag` BOOLEAN COMMENT 'Indicates whether payments under this program require managerial or financial approval before processing.',
    `approved_by_user_id` BIGINT COMMENT 'Identifier of the user who approved the payment program for activation.',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time when the payment program was formally approved for activation.',
    `audit_trail_required_flag` BOOLEAN COMMENT 'Indicates whether detailed audit trails must be maintained for all payments processed under this program.',
    `auto_renew_flag` BOOLEAN COMMENT 'Indicates whether the payment program automatically renews upon expiration or requires manual renewal.',
    `base_rate` DECIMAL(18,2) COMMENT 'Base payment rate or percentage used as the foundation for calculating payments under this program.',
    `business_unit_id` BIGINT COMMENT 'Identifier of the business unit or division responsible for managing and funding this payment program.',
    `contract_template_id` BIGINT COMMENT 'Identifier of the standard contract template associated with this payment program for legal and compliance purposes.',
    `cost_center_code` STRING COMMENT 'Cost center code for expense allocation and budgetary control of payments made under this program.',
    `created_by_user_id` BIGINT COMMENT 'Identifier of the user who created the payment program record.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when the payment program record was first created in the system.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code in which payments under this program are denominated.',
    `payment_program_description` STRING COMMENT 'Detailed business description of the payment program including its purpose, scope, and key terms.',
    `effective_end_date` DATE COMMENT 'Date when the payment program expires or is terminated. Null for open-ended programs.',
    `effective_start_date` DATE COMMENT 'Date when the payment program becomes active and eligible for processing payments.',
    `gl_account_code` STRING COMMENT 'General ledger account code to which payments under this program are posted for financial reporting and SOX compliance.',
    `grace_period_days` STRING COMMENT 'Number of days after payment due date during which late fees or penalties are not applied.',
    `last_modified_by_user_id` BIGINT COMMENT 'Identifier of the user who last modified the payment program record.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Date and time when the payment program record was last updated.',
    `late_fee_percentage` DECIMAL(18,2) COMMENT 'Percentage fee applied to late payments under this program after the grace period expires.',
    `maximum_payment_amount` DECIMAL(18,2) COMMENT 'Maximum payment cap that limits the amount that can be paid in a single payment cycle under this program.',
    `minimum_payment_amount` DECIMAL(18,2) COMMENT 'Minimum payment threshold that must be met for a payment to be processed under this program.',
    `notes` STRING COMMENT 'Additional free-form notes or comments about the payment program for internal reference.',
    `payment_frequency` STRING COMMENT 'Cadence at which payments are processed and distributed under this program.',
    `payment_method` STRING COMMENT 'Default payment instrument or mechanism used to disburse payments under this program.',
    `payment_terms_days` STRING COMMENT 'Number of days from invoice or event date until payment is due under this program.',
    `program_code` STRING COMMENT 'Unique business identifier code for the payment program used in external communications and financial reporting.',
    `program_name` STRING COMMENT 'Full descriptive name of the payment program as displayed to users and in financial reports.',
    `program_owner_employee_id` BIGINT COMMENT 'Identifier of the employee responsible for managing and overseeing this payment program.',
    `program_type` STRING COMMENT 'Classification of the payment program structure determining how payments are calculated and distributed.',
    `rate_unit` STRING COMMENT 'Unit of measure for the base rate indicating how the rate is applied in payment calculations.',
    `revenue_recognition_method` STRING COMMENT 'Method used for recognizing revenue associated with this payment program in accordance with accounting standards.',
    `sox_control_flag` BOOLEAN COMMENT 'Indicates whether this payment program is subject to SOX financial controls and audit requirements.',
    `payment_program_status` STRING COMMENT 'Current lifecycle status of the payment program indicating whether it is operational and available for use.',
    `tax_treatment_code` STRING COMMENT 'Code indicating the tax treatment classification for payments under this program for compliance and reporting purposes.',
    `termination_reason` STRING COMMENT 'Business reason or justification for terminating or suspending the payment program.',
    `version_number` STRING COMMENT 'Version number of the payment program configuration for tracking changes and maintaining audit history.',
    CONSTRAINT pk_payment_program PRIMARY KEY(`payment_program_id`)
) COMMENT 'Master reference table for payment_program. Referenced by payment_program_id.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`finance`.`payment_proposal` (
    `payment_proposal_id` BIGINT COMMENT 'Primary key for payment_proposal',
    `revised_payment_proposal_id` BIGINT COMMENT 'Self-referencing FK on payment_proposal (revised_payment_proposal_id)',
    `adjustment_amount` DECIMAL(18,2) COMMENT 'Any additional adjustments (positive or negative) applied to the payment amount, such as credits, debits, or corrections.',
    `approval_required_flag` BOOLEAN COMMENT 'Indicates whether this payment proposal requires explicit management approval before execution.',
    `approval_timestamp` TIMESTAMP COMMENT 'The date and time when the payment proposal was approved.',
    `approved_by_user_id` BIGINT COMMENT 'Identifier of the user who approved this payment proposal.',
    `bank_account_id` BIGINT COMMENT 'Identifier of the company bank account from which the payment will be disbursed.',
    `company_code` STRING COMMENT 'The organizational unit or legal entity code within the enterprise that is responsible for this payment.',
    `cost_center_code` STRING COMMENT 'The cost center to which this payment expense is allocated for internal financial reporting and budgeting.',
    `created_by_user_id` BIGINT COMMENT 'Identifier of the user who created this payment proposal record.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this payment proposal record was first created in the system.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for the payment amount (e.g., USD, EUR, GBP).',
    `discount_amount` DECIMAL(18,2) COMMENT 'The early payment discount amount that can be taken if payment is made by the discount due date.',
    `discount_due_date` DATE COMMENT 'The date by which payment must be made to qualify for early payment discount terms.',
    `due_date` DATE COMMENT 'The contractual due date by which payment must be made to the vendor to avoid penalties or late fees.',
    `executed_timestamp` TIMESTAMP COMMENT 'The date and time when the payment was actually executed and funds were disbursed.',
    `general_ledger_account` STRING COMMENT 'The general ledger account number to which this payment will be posted in the chart of accounts.',
    `gross_amount` DECIMAL(18,2) COMMENT 'The total invoice amount before any deductions, discounts, or adjustments.',
    `intercompany_flag` BOOLEAN COMMENT 'Indicates whether this payment is an intercompany transaction between legal entities within the same corporate group.',
    `invoice_id` BIGINT COMMENT 'Identifier of the invoice document that this payment proposal settles or partially settles.',
    `modified_by_user_id` BIGINT COMMENT 'Identifier of the user who last modified this payment proposal record.',
    `modified_timestamp` TIMESTAMP COMMENT 'The date and time when this payment proposal record was last modified.',
    `net_payment_amount` DECIMAL(18,2) COMMENT 'The final payment amount after applying discounts, withholding taxes, and adjustments. This is the amount proposed for disbursement.',
    `notes` STRING COMMENT 'Free-text field for additional comments, instructions, or context related to this payment proposal.',
    `payment_block_code` STRING COMMENT 'Code indicating if the payment is blocked from execution, and the reason for the block (e.g., dispute, compliance hold).',
    `payment_method` STRING COMMENT 'The financial instrument or mechanism proposed for executing the payment (e.g., wire transfer, ACH, check).',
    `payment_priority` STRING COMMENT 'The priority level assigned to this payment proposal for sequencing and cash flow management.',
    `payment_reference_number` STRING COMMENT 'External reference number or remittance advice identifier to be included with the payment for vendor reconciliation.',
    `payment_term_code` STRING COMMENT 'Code representing the contractual payment terms (e.g., NET30, NET60, 2/10NET30) governing this proposal.',
    `payment_transaction_id` STRING COMMENT 'The unique transaction identifier assigned by the payment processing system or bank when the payment was executed.',
    `proposal_date` DATE COMMENT 'The business date on which the payment proposal was created or submitted for approval.',
    `proposal_number` STRING COMMENT 'Externally visible unique business identifier for the payment proposal, formatted as PP-NNNNNNNN.',
    `proposal_run_id` BIGINT COMMENT 'Identifier linking this payment proposal to a specific proposal run batch execution.',
    `proposal_status` STRING COMMENT 'Current lifecycle status of the payment proposal in the approval and execution workflow.',
    `rejection_reason` STRING COMMENT 'Free-text explanation of why the payment proposal was rejected, if applicable.',
    `scheduled_payment_date` DATE COMMENT 'The target date on which the payment is scheduled to be executed if approved.',
    `sox_compliant_flag` BOOLEAN COMMENT 'Indicates whether this payment proposal has passed all Sarbanes-Oxley internal control checks and segregation of duties requirements.',
    `vendor_bank_account_id` BIGINT COMMENT 'Identifier of the vendor bank account to which the payment will be sent.',
    `vendor_id` BIGINT COMMENT 'Identifier of the vendor or supplier to whom payment is proposed.',
    `withholding_tax_amount` DECIMAL(18,2) COMMENT 'The amount of tax withheld at source as required by tax regulations for this payment.',
    CONSTRAINT pk_payment_proposal PRIMARY KEY(`payment_proposal_id`)
) COMMENT 'Master reference table for payment_proposal. Referenced by proposal_run_id.';

